/**
 * A threshold range
 * @public
 */
export interface ColoredRange {
    /** Range starting point */
    from: number;
    /** Range ending point */
    to: number;
    /** The color to use in this range  */
    color?: string;
}
/**
 * @internal
 */
export declare function isColoredRangeArray(colorRange: unknown): colorRange is ColoredRange[];
